// Contenu narratif du mode cartes. CE FICHIER est la SOURCE DE VÉRITÉ des cartes
// (docs/train_cosy_arc.twee ne décrit que l'ARC, pas les fillers). 14 gares (avec
// variantes selon flags) + un paquet de remplissage par segment, taggé
// repeatable / oneshot pour le tirage.
//
// Flags utilisés : aLeChien (chien recueilli),
// aLaSoeur (sœur retrouvée gare 5), soeurProtegee (gestes de soin,
// compte cardSoin), capParents, indiceSoeur, aLaRadio + chaîne radio1/2/3
// (arc radio -> fin secrète), asset_bed/filter/hydro (déblocage d'objets).

import '../models/game_state.dart';
import '../models/reigns_engine.dart';

// Raccourcis pour alléger l'écriture.
CardChoice _c(
  String label, {
  Map<Stat, int> fx = const {},
  List<String> flags = const [],
  String? result,
  String? reaction, // réplique d'un perso à ce choix (sœur/chien/radio)
}) =>
    CardChoice(
      label: label,
      effects: fx,
      setFlags: flags,
      resultText: result,
      reaction: reaction,
    );

StoryCard _filler(
  String id,
  String text,
  CardChoice left,
  CardChoice right, {
  bool oneshot = false,
  bool Function(Set<String>)? requires,
  CardArt art = CardArt.none,
  bool hidden = false, // enjeu caché (pari)
}) =>
    StoryCard(
      id: id,
      kind: oneshot ? CardKind.fillerOneshot : CardKind.fillerRepeatable,
      text: text,
      left: left,
      right: right,
      requires: requires,
      art: art,
      hiddenStakes: hidden,
    );

/// Épreuve de gare (choix pur, pas de mini-jeu) : la menace de la gare devient
/// une carte à 2 choix, chacun menant DIRECTEMENT à sa conséquence (pas de
/// stat-check caché). C'est ainsi que se résolvent les beats de danger.
StoryCard _epreuve(String id, String speaker, String text,
        CardChoice left, CardChoice right,
        {CardArt art = CardArt.none}) =>
    StoryCard(
        id: id, kind: CardKind.gare, speaker: speaker,
        text: text, left: left, right: right, art: art);

// ============================================================
// LES 14 GARES (piliers narratifs) — ARC PETITE SŒUR
// 1→4 : la fuite, Shen seule, un espoir qu'elle refoule.
// 5    : RETROUVAILLES surprise avec la petite sœur (flag aLaSoeur).
// 6→14 : la protéger (2 bouches : faim/soif plus dures, moral soutenu)
//        et tenir jusqu'au refuge nord OÙ LES PARENTS ATTENDENT.
// ============================================================

List<StoryCard> _gare1(Set<String> f) => [
      // GARE 1 = LA FUITE de Kogarashi (ta ville natale, qui brûle). On ne s'y
      // arrête pas pour récupérer un chien : on la FUIT. Le chiot est au 1er
      // vrai arrêt (Kurogane, gare 2). Ici : la fuite + la perte + la paillasse.
      StoryCard(
        id: 'G1',
        kind: CardKind.gare,
        speaker: 'Kogarashi',
        art: CardArt.fire,
        text:
            "Kogarashi brûle. Le train s'arrache à ta ville en flammes — et toi avec, sans avoir eu le choix. Recroquevillée au fond du train, tu regardes ta maison, ta rue, ta vie entière disparaître dans le rougeoiement.",
        left: _c("Regarder jusqu'au bout, graver l'image",
            fx: {Stat.moral: -7, Stat.bois: 6}, flags: ['asset_bed'],
            result: "Tu fixes les flammes jusqu'à ce que la nuit les avale. Tu n'oublieras pas. Jamais. La rage te fait arracher des planches calcinées au quai : du bois pour la loco. Puis tu pousses une paillasse dans un coin du wagon : ton premier couchage."),
        right: _c("Te détourner, survivre d'abord",
            fx: {Stat.moral: 8, Stat.faim: -5}, flags: ['asset_bed'],
            result: "Assez regardé en arrière. Tu te détournes des flammes, l'estomac noué de t'être enfuie sans rien — mais le regard droit. Tu pousses une paillasse dans un coin du wagon : ton premier couchage. Demain, il faudra tenir."),
      ),
      StoryCard(
        id: 'G1c',
        kind: CardKind.gare,
        speaker: 'Kogarashi',
        art: CardArt.memory,
        text:
            "La nuit tombe sur un monde noir. Tu revois la cohue : tes parents qui te poussaient en avant, la main de ta sœur arrachée à la tienne. Tu n'as vu personne tomber — mais personne s'en sortir non plus.",
        left: _c("Te jurer de les retrouver",
            fx: {Stat.moral: 11, Stat.bois: -6},
            result: "Tu serres les poings et tu pousses la loco dans la nuit, sans économiser le feu : tant qu'il n'y a pas de preuve, tu choisis d'espérer et d'avancer. Ça brûle du bois, mais c'est ça qui te fera tenir."),
        right: _c("Te préparer au pire",
            fx: {Stat.moral: -8, Stat.faim: 6},
            result: "Tu enterres l'espoir avant qu'il ne te brise. À froid, tu rationnes, tu comptes, tu mets de côté. Tu avanceras quand même. Autrement."),
      ),
    ];

